import axios from 'axios';
import { pushToast } from '../utils/toastBridge';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3000/api';

// Create axios instance
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

const MUTATING_METHODS = new Set(['post', 'put', 'patch', 'delete'])

const DEFAULT_SUCCESS_BY_METHOD = {
  post: 'Thêm mới thành công',
  put: 'Cập nhật thành công',
  patch: 'Cập nhật thành công',
  delete: 'Xóa thành công',
}

const isAuthRoute = (url = '') => {
  return url.startsWith('/auth/login') || url.startsWith('/auth/refresh-token')
}

const shouldShowAutoToast = (config = {}) => {
  const method = (config.method || '').toLowerCase()
  if (!MUTATING_METHODS.has(method)) return false
  if (config.toast === false || config.skipToast === true) return false
  if (isAuthRoute(config.url || '')) return false
  return true
}

const extractServerMessage = (payload) => {
  if (!payload || typeof payload !== 'object') return null
  return payload.message || payload.error || payload?.data?.message || null
}

// Add token to requests
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Handle responses
apiClient.interceptors.response.use(
  (response) => {
    const { config, data } = response
    if (shouldShowAutoToast(config)) {
      const method = (config.method || '').toLowerCase()
      const successMessage = typeof config.toast === 'object' && config.toast?.success
        ? config.toast.success
        : (extractServerMessage(data) || DEFAULT_SUCCESS_BY_METHOD[method] || 'Thao tác thành công')

      pushToast({
        title: 'Thành công',
        message: successMessage,
        type: 'success',
        duration: 3500,
      })
    }
    return response
  },
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }

    const config = error.config || {}
    if (shouldShowAutoToast(config)) {
      const errorMessage = typeof config.toast === 'object' && config.toast?.error
        ? config.toast.error
        : (extractServerMessage(error.response?.data) || error.message || 'Thao tác thất bại')

      pushToast({
        title: 'Thất bại',
        message: errorMessage,
        type: 'error',
        duration: 5000,
      })
    }

    return Promise.reject(error);
  }
);

// =============== AUTH ENDPOINTS ===============
export const authService = {
  register: (fullName, username, email, password, passwordConfirm, farmName) =>
    apiClient.post('/auth/register', { fullName, username, email, password, passwordConfirm, farmName }),
  
  login: (username, password) =>
    apiClient.post('/auth/login', { username, password }),
  
  refreshToken: () =>
    apiClient.post('/auth/refresh-token'),
  
  changePassword: (data) =>
    apiClient.post('/auth/change-password', data),
};

// =============== USER ENDPOINTS ===============
export const userService = {
  getCurrentUser: () =>
    apiClient.get('/users/me'),
  
  getAllUsers: () =>
    apiClient.get('/users'),

  getWorkers: () =>
    apiClient.get('/users/workers'),
  
  updateUser: (userId, userData) =>
    apiClient.put(`/users/${userId}`, userData),
  
  updateUserRole: (userId, roleId) =>
    apiClient.put(`/users/${userId}/role`, { role_id: roleId }),
  
  lockUser: (userId) =>
    apiClient.put(`/users/${userId}/lock`),
  
  unlockUser: (userId) =>
    apiClient.put(`/users/${userId}/unlock`),
  
  resetPassword: (userId) =>
    apiClient.post(`/users/${userId}/reset-password`),
  
  deleteUser: (userId) =>
    apiClient.delete(`/users/${userId}`),

  // Update role by name (e.g., 'MANAGER') - used by Owner interface
  updateUserRoleByName: (userId, roleName) =>
    apiClient.put(`/users/${userId}/role`, { role: roleName }),

  // Remove user from farm (set farm_id = NULL)
  removeFromFarm: (userId) =>
    apiClient.put(`/users/${userId}/remove-from-farm`),

  // Assign user to farm (set farm_id)
  assignToFarm: (userId, farmId) =>
    apiClient.put(`/users/${userId}/assign-to-farm`, { farm_id: farmId }),
  
  changePassword: (oldPassword, newPassword) =>
    apiClient.post('/users/change-password', { oldPassword, newPassword }),
  
  updateProfile: (userData) =>
    apiClient.put('/users/me', userData),

  updateProfileAvatar: (formData) =>
    apiClient.post('/users/me/avatar', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    }),
};

// =============== ADMIN ENDPOINTS ===============
export const adminService = {
  // Users Management
  getAllUsers: () =>
    apiClient.get('/admin/users'),
  
  createUser: (userData) =>
    apiClient.post('/admin/users', userData),
  
  lockUser: (userId) =>
    apiClient.post(`/admin/users/${userId}/lock`),
  
  unlockUser: (userId) =>
    apiClient.post(`/admin/users/${userId}/unlock`),
  
  getFarms: () =>
    apiClient.get('/admin/farms'),
  
  getUserLoginLogs: (userId) =>
    apiClient.get(`/admin/users/${userId}/login-logs`),
  
  // Stats
  getSystemStats: () =>
    apiClient.get('/admin/stats/overview'),
  
  getUserStats: () =>
    apiClient.get('/admin/stats/users'),
  
  getPondStats: () =>
    apiClient.get('/admin/stats/ponds'),
  
  getSeasonStats: () =>
    apiClient.get('/admin/stats/seasons'),
  
  // Reports
  getProductionReport: () =>
    apiClient.get('/admin/reports/production'),
  
  getFinancialReport: () =>
    apiClient.get('/admin/reports/financial'),
  
  getHealthReport: () =>
    apiClient.get('/admin/reports/health'),
  
  // Activity Logs
  getActivityLogs: (filters = {}) =>
    apiClient.get('/admin/activity-logs', { params: filters }),
  
  // AI Management
  getTrainingData: () =>
    apiClient.get('/admin/ai/training-data'),
  
  uploadTrainingData: (formData) =>
    apiClient.post('/admin/ai/training-data', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    }),
  
  deleteTrainingData: (dataId) =>
    apiClient.delete(`/admin/ai/training-data/${dataId}`),
  
  getPredictionHistory: () =>
    apiClient.get('/admin/ai/predictions'),
  
  updateAIModel: (modelData) =>
    apiClient.post('/admin/ai/model/update', modelData),
  
  getModelStatus: () =>
    apiClient.get('/admin/ai/model/status'),
  
  // Data Summary
  getDataSummary: () =>
    apiClient.get('/admin/data/summary'),
};

// =============== POND ENDPOINTS ===============
export const pondService = {
  getAllPonds: () =>
    apiClient.get('/ponds'),
  
  getPondById: (pondId) =>
    apiClient.get(`/ponds/${pondId}`),
  
  createPond: (pondData) =>
    apiClient.post('/ponds', pondData),
  
  updatePond: (pondId, pondData) =>
    apiClient.put(`/ponds/${pondId}`, pondData),
  
  deletePond: (pondId) =>
    apiClient.delete(`/ponds/${pondId}`),
  
  assignStaff: (pondId, staffId) =>
    apiClient.post(`/ponds/${pondId}/assign-staff`, { staffId }),
};


// =============== SEASON ENDPOINTS ===============
export const seasonService = {
  getAllSeasons: (params = {}) =>
    apiClient.get('/seasons', { params }),
  
  getSeasonById: (seasonId) =>
    apiClient.get(`/seasons/${seasonId}`),
  
  createSeason: (seasonData) =>
    apiClient.post('/seasons', seasonData),
  
  updateSeason: (seasonId, seasonData) =>
    apiClient.put(`/seasons/${seasonId}`, seasonData),
  
  deleteSeason: (seasonId) =>
    apiClient.delete(`/seasons/${seasonId}`),
  
  harvestSeason: (seasonId, data) =>
    apiClient.post(`/seasons/${seasonId}/harvest`, data),
};

// =============== CULTIVATION LOG ENDPOINTS ===============
export const cultivationLogService = {
  getBySeasonId: (seasonId) =>
    apiClient.get(`/cultivation-logs/season/${seasonId}`),
  
  getByPondId: (pondId) =>
    apiClient.get(`/cultivation-logs/pond/${pondId}`),
  
  createLog: (logData) =>
    apiClient.post('/cultivation-logs', logData),
  
  updateLog: (logId, logData) =>
    apiClient.put(`/cultivation-logs/${logId}`, logData),
  
  approveLog: (logId) =>
    apiClient.post(`/cultivation-logs/${logId}/approve`),
  
  rejectLog: (logId, reason) =>
    apiClient.post(`/cultivation-logs/${logId}/reject`, { reason }),
  
  lockLogByDate: (seasonId, date) =>
    apiClient.post(`/cultivation-logs/season/${seasonId}/lock-date`, { lockDate: date }),
};

// =============== TASK ENDPOINTS ===============
export const taskService = {
  getAllTasks: () =>
    apiClient.get('/tasks'),
  
  getTaskById: (taskId) =>
    apiClient.get(`/tasks/${taskId}`),
  
  createTask: (taskData) =>
    apiClient.post('/tasks', taskData),
  
  updateTask: (taskId, taskData) =>
    apiClient.put(`/tasks/${taskId}`, taskData),
  
  deleteTask: (taskId) =>
    apiClient.delete(`/tasks/${taskId}`),
  
